import { compile } from './src/compiler/index.js';

// Test case 1: Static method should not conflict with instance method
const staticMethodTest = `
<script>
class Hello {
  hello() {}
  static hello() {}
}
</script>
`;

// Test case 2: Static property should not conflict with instance property
const staticPropertyTest = `
<script>
class Hello {
  count = 0;
  static count = 1;
}
</script>
`;

// Test case 3: Static method should not conflict with instance property
const staticMethodPropertyTest = `
<script>
class Hello {
  count = 0;
  static count() {}
}
</script>
`;

// Test case 4: Instance method conflict should still be caught (should fail)
const instanceConflictTest = `
<script>
class Hello {
  hello() {}
  hello() {} // This should throw an error
}
</script>
`;

console.log('=== Testing static method/property conflicts (should all pass) ===');

try {
  compile(staticMethodTest);
  console.log('✅ Test 1: Static method + instance method - passed');
} catch (error) {
  console.log('❌ Test 1: Static method + instance method - failed:', error.message);
}

try {
  compile(staticPropertyTest);
  console.log('✅ Test 2: Static property + instance property - passed');
} catch (error) {
  console.log('❌ Test 2: Static property + instance property - failed:', error.message);
}

try {
  compile(staticMethodPropertyTest);
  console.log('✅ Test 3: Static method + instance property - passed');
} catch (error) {
  console.log('❌ Test 3: Static method + instance property - failed:', error.message);
}

console.log('\n=== Testing instance conflict (should fail) ===');

try {
  compile(instanceConflictTest);
  console.log('❌ Test 4: Instance method conflict - should have failed but didn\'t');
} catch (error) {
  console.log('✅ Test 4: Instance method conflict - correctly failed:', error.message);
}

console.log('\n=== All tests completed ===');

